import type { DMMF } from '@prisma/generator-helper'

/**
 * Maps a Prisma scalar type name to the corresponding TypeScript primitive type.
 * Returns the input unchanged for enum and object (relation) types so they resolve
 * to the generated interface names.
 */
export function mapPrismaTypeToTs(field: DMMF.Field): string {
  if (field.kind !== 'scalar') {
    // Enum and object (relation) types use the Prisma type name, which matches
    // the generated interface name.
    return field.type
  }

  switch (field.type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

/** Returns the full TypeScript type annotation for a field, handling lists and nullability. */
export function fieldTypeAnnotation(field: DMMF.Field): string {
  const base = mapPrismaTypeToTs(field)
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/**
 * Converts a PascalCase model name to a kebab-case plural URL path segment.
 * For example: `UserProfile` → `user-profiles`, `Post` → `posts`.
 */
export function modelNameToPath(name: string): string {
  const kebab = name
    .replace(/([a-z\d])([A-Z])/g, '$1-$2')
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
  return pluralize(kebab)
}

function pluralize(word: string): string {
  if (/(?:s|x|z|ch|sh)$/.test(word)) return `${word}es`
  if (/[^aeiou]y$/.test(word)) return `${word.slice(0, -1)}ies`
  return `${word}s`
}

/** Scalar and enum fields only — relation fields are excluded from generated types. */
function scalarAndEnumFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind !== 'object')
}

/**
 * Fields used in `WhereUniqueInput`: those marked `@id` or `@unique`.
 * Compound unique indexes are not represented here for simplicity.
 */
function uniqueIdentifierFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.isId || f.isUnique)
}

/**
 * Fields included in `CreateInput`: scalar/enum fields that are not auto-generated
 * IDs, not `@updatedAt`, and not otherwise managed by the database.
 */
function createableFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => {
    if (f.kind === 'object') return false
    if (f.isId && f.hasDefaultValue) return false
    if (f.isGenerated) return false
    if (f.isUpdatedAt) return false
    return true
  })
}

/** Generates a `TypeScript` interface declaration for a model's scalar fields. */
export function generateModelInterface(model: DMMF.Model): string {
  const fields = scalarAndEnumFields(model)
  const members = fields.map((f) => `  ${f.name}: ${fieldTypeAnnotation(f)}`)
  return [`export interface ${model.name} {`, ...members, '}'].join('\n')
}

/**
 * Generates a `WhereUniqueInput` interface with all `@id` / `@unique` fields
 * as optional properties (callers provide exactly one).
 */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = uniqueIdentifierFields(model)
  if (fields.length === 0) return ''
  const members = fields.map((f) => `  ${f.name}?: ${mapPrismaTypeToTs(f)}`)
  return [`export interface ${model.name}WhereUniqueInput {`, ...members, '}'].join('\n')
}

/**
 * Generates a `CreateInput` interface.  Required fields without defaults are
 * mandatory; optional and defaulted fields carry `?`.
 */
export function generateCreateInput(model: DMMF.Model): string {
  const fields = createableFields(model)
  const members = fields.map((f) => {
    const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
    const tsType = mapPrismaTypeToTs(f)
    const nullable = !f.isRequired ? ` | null` : ''
    return `  ${f.name}${optional}: ${tsType}${nullable}`
  })
  return [`export interface ${model.name}CreateInput {`, ...members, '}'].join('\n')
}

/** Generates the TypeScript interface that describes the public API of one model's client. */
export function generateModelClientInterface(model: DMMF.Model): string {
  const n = model.name
  return [
    `export interface ${n}Client {`,
    `  findMany(params?: { where?: Partial<${n}> }): Promise<${n}[]>`,
    `  findUnique(params: { where: ${n}WhereUniqueInput }): Promise<${n} | null>`,
    `  create(params: { data: ${n}CreateInput }): Promise<${n}>`,
    `  update(params: { where: ${n}WhereUniqueInput; data: Partial<${n}CreateInput> }): Promise<${n}>`,
    `  delete(params: { where: ${n}WhereUniqueInput }): Promise<${n}>`,
    '}',
  ].join('\n')
}

/** Generates the concrete class that implements `{Model}Client` via HTTP fetch calls. */
export function generateModelClientClass(model: DMMF.Model): string {
  const n = model.name
  const urlPath = modelNameToPath(n)

  return `class ${n}RestClient implements ${n}Client {
  readonly #baseUrl: string
  readonly #options: RestClientOptions

  constructor(baseUrl: string, options: RestClientOptions) {
    this.#baseUrl = baseUrl
    this.#options = options
  }

  async findMany(params?: { where?: Partial<${n}> }): Promise<${n}[]> {
    const url = new URL(\`\${this.#baseUrl}/${urlPath}\`)
    if (params?.where) {
      for (const [key, value] of Object.entries(params.where)) {
        if (value !== undefined && value !== null) {
          url.searchParams.set(key, String(value))
        }
      }
    }
    return this.#request<${n}[]>(url.toString(), { method: 'GET' })
  }

  async findUnique(params: { where: ${n}WhereUniqueInput }): Promise<${n} | null> {
    const id = pickFirstDefined(params.where)
    const response = await this.#rawFetch(\`\${this.#baseUrl}/${urlPath}/\${id}\`, { method: 'GET' })
    if (response.status === 404) return null
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<${n}>
  }

  async create(params: { data: ${n}CreateInput }): Promise<${n}> {
    return this.#request<${n}>(\`\${this.#baseUrl}/${urlPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
  }

  async update(params: { where: ${n}WhereUniqueInput; data: Partial<${n}CreateInput> }): Promise<${n}> {
    const id = pickFirstDefined(params.where)
    return this.#request<${n}>(\`\${this.#baseUrl}/${urlPath}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
  }

  async delete(params: { where: ${n}WhereUniqueInput }): Promise<${n}> {
    const id = pickFirstDefined(params.where)
    return this.#request<${n}>(\`\${this.#baseUrl}/${urlPath}/\${id}\`, { method: 'DELETE' })
  }

  async #request<T>(url: string, init: RequestInit): Promise<T> {
    const response = await this.#rawFetch(url, init)
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<T>
  }

  #rawFetch(url: string, init: RequestInit): Promise<Response> {
    const fetchFn = this.#options.fetch ?? globalThis.fetch
    const extraHeaders = init.headers as Record<string, string> | undefined
    const headers = { ...this.#options.headers, ...extraHeaders }
    return fetchFn(url, { ...init, headers })
  }
}`
}

/** Generates the top-level `RestClient` class that exposes one sub-client per model. */
export function generateRestClientClass(models: readonly DMMF.Model[]): string {
  const fields = models.map((m) => {
    const camel = `${m.name[0].toLowerCase()}${m.name.slice(1)}`
    return `  readonly ${camel}: ${m.name}Client`
  })

  const assignments = models.map((m) => {
    const camel = `${m.name[0].toLowerCase()}${m.name.slice(1)}`
    return `    this.${camel} = new ${m.name}RestClient(baseUrl, options)`
  })

  return [
    'export class RestClient {',
    ...fields,
    '',
    '  constructor(baseUrl: string, options: RestClientOptions = {}) {',
    ...assignments,
    '  }',
    '}',
  ].join('\n')
}

/**
 * Assembles the full source of the generated `rest-client.ts` file from the
 * DMMF document produced by Prisma's schema compiler.
 */
export function buildRestClientSource(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models
  const parts: string[] = []

  parts.push('// Auto-generated by @prisma/generator-rest-client. Do not edit manually.')
  parts.push('')

  // Model interfaces
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('// Model interfaces')
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('')
  for (const model of models) {
    parts.push(generateModelInterface(model))
    parts.push('')
  }

  // Input type interfaces
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('// Input type interfaces')
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('')
  for (const model of models) {
    const whereUnique = generateWhereUniqueInput(model)
    if (whereUnique) {
      parts.push(whereUnique)
      parts.push('')
    }
    parts.push(generateCreateInput(model))
    parts.push('')
  }

  // Per-model client interfaces
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('// Per-model client interfaces')
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('')
  for (const model of models) {
    parts.push(generateModelClientInterface(model))
    parts.push('')
  }

  // Shared types and utilities
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('// Shared types and utilities')
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('')
  parts.push(`export interface RestClientOptions {
  /** Default headers sent with every request. */
  headers?: Record<string, string>
  /** Custom fetch implementation. Defaults to \`globalThis.fetch\`. */
  fetch?: typeof fetch
}`)
  parts.push('')
  parts.push(`/** Thrown when the server returns a non-2xx HTTP status code. */
export class RestClientError extends Error {
  readonly status: number

  constructor(status: number, body: string) {
    super(\`HTTP \${status}: \${body}\`)
    this.name = 'RestClientError'
    this.status = status
  }
}`)
  parts.push('')

  // Internal helper — not exported because callers work through the typed client interfaces
  parts.push(`function pickFirstDefined(where: Record<string, unknown>): unknown {
  const entry = Object.entries(where).find(([, v]) => v !== undefined)
  if (!entry) throw new Error('No field provided in where clause')
  return entry[1]
}`)
  parts.push('')

  // Per-model client implementations
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('// Per-model client implementations (internal)')
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('')
  for (const model of models) {
    parts.push(generateModelClientClass(model))
    parts.push('')
  }

  // Main entry point
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('// Main client class')
  parts.push('// ---------------------------------------------------------------------------')
  parts.push('')
  parts.push(generateRestClientClass(models))
  parts.push('')

  return parts.join('\n')
}

