import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator-helper'

import { buildRestClientSource } from './template'

/**
 * Runs the REST client generation step.
 *
 * Reads the DMMF from `options.dmmf`, renders all model interfaces, input
 * types, and client classes, then writes a single `rest-client.ts` file into
 * the configured output directory.
